function clamp(r,n,t){return Math.min(Math.max(r,n),t)}function squaredSegmentDistance(r,n,t,e,o,a){var u,i=o-t,c=a-e;return 0==i&&0==c||(1<(u=((r-t)*i+(n-e)*c)/(i*i+c*c))?(t=o,e=a):0<u&&(t+=i*u,e+=c*u)),squaredDistance(r,n,t,e)}function squaredDistance(r,n,t,e){t-=r,r=e-n;return t*t+r*r}function solveLinearSystem(r){for(var n=r.length,t=0;t<n;t++){for(var e=t,o=Math.abs(r[t][t]),a=t+1;a<n;a++){var u=Math.abs(r[a][t]);o<u&&(o=u,e=a)}if(0===o)return null;var i=r[e];r[e]=r[t],r[t]=i;for(var c=t+1;c<n;c++)for(var f=-r[c][t]/r[t][t],s=t;s<n+1;s++)t==s?r[c][s]=0:r[c][s]+=f*r[t][s]}for(var d=new Array(n),l=n-1;0<=l;l--){d[l]=r[l][n]/r[l][l];for(var h=l-1;0<=h;h--)r[h][n]-=r[h][l]*d[l]}return d}function toDegrees(r){return 180*r/Math.PI}function toRadians(r){return r*Math.PI/180}function modulo(r,n){r%=n;return r*n<0?r+n:r}function lerp(r,n,t){return r+t*(n-r)}function toFixed(r,n){n=Math.pow(10,n);return Math.round(r*n)/n}function round(r,n){return Math.round(toFixed(r,n))}function floor(r,n){return Math.floor(toFixed(r,n))}function ceil(r,n){return Math.ceil(toFixed(r,n))}export{clamp,squaredSegmentDistance,squaredDistance,solveLinearSystem,toDegrees,toRadians,modulo,lerp,toFixed,round,floor,ceil};